#version 300 es
precision highp float;

// VisualSynth uniforms
uniform float uTime;
uniform float uFrame;
uniform float uFps;
uniform float uRms;

// Audio uniforms
uniform float audioLow;      // bass
uniform float audioLowSmooth; // bass_att
uniform float audioMid;      // mid
uniform float audioMidSmooth; // mid_att
uniform float audioHigh;     // treb
uniform float audioHighSmooth; // treb_att

// Screen uniforms
uniform float uAspectX;
uniform float uAspectY;
uniform vec2 uAspect;
uniform vec2 uTexSize;

// Random values
uniform vec2 uRandomPreset;
uniform vec2 uRandomFrame;

// Input from vertex shader
in vec2 vUv;
in float vRadius;
in float vAngle;

// Output
out vec4 fragColor;

// Textures
uniform sampler2D sampler_main;
uniform sampler2D sampler_noise_lq;
uniform sampler2D sampler_noise_mq;
uniform sampler2D sampler_noise_hq;
uniform sampler2D sampler_blur1;
uniform sampler2D sampler_blur2;
uniform sampler2D sampler_blur3;

// Helper functions
float clamp01(float x) { return clamp(x, 0.0, 1.0); }
vec2 clamp01(vec2 x) { return clamp(x, vec2(0.0), vec2(1.0)); }
vec3 clamp01(vec3 x) { return clamp(x, vec3(0.0), vec3(1.0)); }
vec4 clamp01(vec4 x) { return clamp(x, vec4(0.0), vec4(1.0)); }

// Texture helper functions
vec4 GetPixel(vec2 uv) { return texture(sampler_main, uv); }
vec4 GetBlur1(vec2 uv) { return texture(sampler_blur1, uv); }
vec4 GetBlur2(vec2 uv) { return texture(sampler_blur2, uv); }
vec4 GetBlur3(vec2 uv) { return texture(sampler_blur3, uv); }


void main() {
  vec4 ret = vec4(0.0);
  vec2 uv = vUv;
  float rad = vRadius;

    vec2 r = vec2(uTexSize.x, uTexSize.y);
    vec2 FC = vUvOriginal * r;
    vec4 o = vec4(0.0, 0.0, 0.0, 0.0);

    // Process all three channels in a single outer loop
    for(int channel = 0; channel < 3; channel++)
    {
        float Z = float(channel - 1); // -1 for red, 0 for green, 1 for blue
        float channelValue = 0.0;
        float skipFlag = 0.0;

        for(float d = 0.0, i = 0.0; i < 80.0; i += 1.0)
        {
            float continueFlag = 1.0 - step(0.5, skipFlag);
            vec3 p = vec3((FC * 2.0 - r) / r.y * d, d - 8.0);

            // Check skip condition
            float skipCondition = step(5.0, abs(p.x));
            skipFlag = max(skipFlag, skipCondition * continueFlag);
            float processFlag = 1.0 - step(0.5, skipFlag);
            #ifdef mouse
            vec2 m = mouse.z > 0 ? (mouse.xy * M_PI) : vec2(uTime / 2, uTime / 2);
            #else
            vec2 m = uTime / 2;
            #endif

            if(processFlag > 0.5)
            {
                // Apply rotations
                p.xz = multiply(rotate2D(m.x), p.xz);
                p.xy = multiply(rotate2D(m.y * 2), p.xy);

                // Grid calculations
                vec3 g = floor(p * 6.0);
                vec3 f = fract(p * 6.0) - 0.5;

                // Random point selection
                float rand1 = fract(sin(dot(g, vec3(127.0, 312.0, 75.0))) * 43758.0);
                float h = step(length(f), rand1 * 0.3 + 0.1);

                // Random angle
                float rand2 = fract(sin(dot(g, vec3(44.0, 78.0, 123.0))) * 127.0);
                float a = rand2 * (M_PI*2);

                // SDF calculation for boxes
                float e = 1.0;
                float sc = 2.0;
                for(int j = 0; j < 3; j++)
                {
                    vec3 g2 = abs(fract(p * sc / 2.0) * 2.0 - 1.0);
                    float m1 = max(g2.x, g2.y);
                    float m2 = max(g2.y, g2.z);
                    float m3 = max(g2.x, g2.z);
                    e = min(e, min(m1, min(m2, m3)) / sc);
                    sc *= 0.6;
                }

                // Combined SDF
                float absX = abs(p.x);
                float absY = abs(p.y);
                float absZ = abs(p.z);
                float dotAbs = dot(vec3(absX, absY, absZ), vec3(0.577, 0.577, 0.577)) * 0.9;
                float c = max(max(max(absX, absY), absZ), dotAbs) - 3.0;

                // Ray marching step
                float sinC = length(sin(c));
                float s = 0.01 + 0.15 * abs(max(max(c, e - 0.1), sinC - 0.3) + Z * 0.02 - i / 130.0);
                d += s;

                // Smooth step
                float sf = smoothstep(0.02, 0.01, s);

                // Color accumulation
                channelValue += 1.6 / s * (0.5 + 0.5 * sin(i * 0.3 + Z * 5.0) +
                                          sf * 4.0 * h * sin(a + i * 0.4 + Z * 5.0));
            }
            else
            {
                // Skip this iteration - increment distance based on skip condition
                d += 1.0 * skipCondition;
            }
        }

        // Assign to appropriate channel
        if(channel == 0) o.r = channelValue;
        else if(channel == 1) o.g = channelValue;
        else o.b = channelValue;
    }

    // Final color processing
    o = o * o / 1.0e7;
    vec4 exp2o = exp(2.0 * o);
    o = (exp2o - 1.0) / (exp2o + 1.0);

    ret = o;

  fragColor = ret;
}

